def unit_of_work(metadata=None, timeout=None):
    def decorator(f):
        def wrapper(*args, **kwargs):
            # 验证参数
            if metadata is not None and not isinstance(metadata, dict):
                raise TypeError("metadata must be a dict or None")

            if timeout is not None:
                if not isinstance(timeout, (int, float)):
                    raise TypeError("timeout must be a number or None")
                if timeout < 0:
                    raise ValueError("timeout cannot be negative")

            # 存储事务配置
            tx_config = {}
            if metadata is not None:
                tx_config["metadata"] = metadata
            if timeout is not None:
                tx_config["timeout"] = timeout

            # 执行事务函数
            def run_tx(tx):
                # 如果有元数据,设置到事务中
                if metadata:
                    tx.set_metadata(metadata)
                # 如果有超时设置,应用到事务中    
                if timeout is not None:
                    tx.set_timeout(timeout)
                # 执行实际的事务函数    
                return f(tx, *args, **kwargs)

            return run_tx

        return wrapper
    return decorator

def index(self, key):
    """
    以整数形式返回键。
    返回给定项的索引。

    :param key: 一个键
    :return: 索引
    :rtype: int
    """
    try:
        return self.keys().index(key)
    except ValueError:
        raise KeyError(f"Key {key} not found")

def values(self, *keys):
    """
    以列表的形式返回通过 `self.index` 过滤的键。
    返回记录的值，可以选择性地通过索引或键进行过滤，仅包含特定的值。

    :param keys: 要包含的项目的索引或键；如果未提供任何参数，则包含所有值
    :return: 值的列表
    :rtype: list
    """
    if not keys:
        # 如果没有提供键，返回所有值
        return list(self.index.values())

    result = []
    for key in keys:
        # 如果key是整数，按索引获取值
        if isinstance(key, int):
            try:
                result.append(list(self.index.values())[key])
            except IndexError:
                continue
        # 否则按键获取值
        else:
            if key in self.index:
                result.append(self.index[key])

    return result

