def check_digests_present_and_used(self, manifest_files, digests_used):
    """
    检查清单（manifest）中所有需要的摘要（digest）是否存在并被使用。在类中返回 `error()`。
    """
    # 遍历所有清单文件
    for manifest in manifest_files:
        # 获取清单中的摘要列表
        manifest_digests = set()
        try:
            for layer in manifest.get('layers', []):
                if 'digest' in layer:
                    manifest_digests.add(layer['digest'])
            if 'config' in manifest and 'digest' in manifest['config']:
                manifest_digests.add(manifest['config']['digest'])
        except (KeyError, TypeError):
            return self.error(f"Invalid manifest format in {manifest}")

        # 检查清单中的摘要是否都被使用
        unused_digests = manifest_digests - set(digests_used)
        if unused_digests:
            return self.error(f"Found unused digests in manifest: {unused_digests}")

        # 检查使用的摘要是否都在清单中
        missing_digests = set(digests_used) - manifest_digests
        if missing_digests:
            return self.error(f"Missing required digests in manifest: {missing_digests}")

    return None

def validate_as_prior_version(self, prior):
    """
    检查 `prior` 是否是当前库存（inventory）对象的有效先前版本。

    输入变量 `prior` 也应是一个 `InventoryValidator` 对象，并且假定 `self` 和 `prior` 的库存对象都已经过内部一致性检查。在类中返回 `error()`。
    """
    # 检查 prior 是否为 InventoryValidator 类型
    if not isinstance(prior, type(self)):
        return self.error("Prior version must be an InventoryValidator object")

    # 检查时间戳,确保 prior 版本早于当前版本
    if prior.timestamp >= self.timestamp:
        return self.error("Prior version must have earlier timestamp")

    # 检查库存变化的合理性
    for item_id in self.inventory:
        # 如果是新增的商品,跳过检查
        if item_id not in prior.inventory:
            continue

        # 检查数量变化是否合理(不能突然减少太多)
        prior_qty = prior.inventory[item_id]
        current_qty = self.inventory[item_id]

        if current_qty < prior_qty * 0.5:  # 假设库存不能突然减少超过50%
            return self.error(f"Suspicious quantity change for item {item_id}")

        # 检查价格变化是否合理(不能突然变化太大)
        prior_price = prior.prices[item_id]
        current_price = self.prices[item_id]

        if abs(current_price - prior_price) > prior_price * 0.3:  # 假设价格变化不能超过30%
            return self.error(f"Suspicious price change for item {item_id}")

    # 所有检查都通过
    return None

def validate_fixity(self, fixity, manifest_files):
    """
    验证库存（inventory）中的校验（fixity）块。检查校验块的结构，并保证仅引用了清单中列出的文件。在类中返回`error()`。
    """
    if not isinstance(fixity, dict):
        return self.error("Fixity block must be a dictionary")

    # Check required fields
    required_fields = ["message-digest-algorithm", "message-digest"]
    for field in required_fields:
        if field not in fixity:
            return self.error(f"Missing required field '{field}' in fixity block")

    # Validate algorithm field
    if not isinstance(fixity["message-digest-algorithm"], str):
        return self.error("message-digest-algorithm must be a string")

    # Validate digest field
    digests = fixity["message-digest"]
    if not isinstance(digests, list):
        return self.error("message-digest must be a list")

    # Check each digest entry
    for digest in digests:
        if not isinstance(digest, dict):
            return self.error("Each message-digest entry must be a dictionary")

        if "file" not in digest or "hash" not in digest:
            return self.error("Each message-digest entry must have 'file' and 'hash' fields")

        if not isinstance(digest["file"], str) or not isinstance(digest["hash"], str):
            return self.error("Digest file and hash values must be strings")

        # Verify file exists in manifest
        if digest["file"] not in manifest_files:
            return self.error(f"Digest references non-existent file: {digest['file']}")

    return None

