    for obj in self.get_all_objects():
        num_objects += 1

        try:
            # 验证对象
            if validate_objects:
                obj.validate()

            # 检查摘要
            if check_digests:
                stored_digest = obj.get_digest()
                calculated_digest = obj.calculate_digest()
                if stored_digest != calculated_digest:
                    if show_warnings:
                        print(f"Warning: Digest mismatch for object {obj.id}")
                    continue

            good_objects += 1

        except Exception as e:
            if show_warnings:
                print(f"Warning: Failed to validate object {obj.id}: {str(e)}")
            continue

    return num_objects, good_objects

def validate_version_inventories(self, version_dirs):
    """
    每个版本**应当**包含截至该版本的完整清单。  

    同时，记录所有与根清单不同的内容摘要，以便在验证内容时能够检查这些差异。  

    `version_dirs` 是一个包含版本目录名称的数组，并假定按照版本顺序排列（1, 2, 3...）。
    """
    # 存储每个版本的清单差异
    version_diffs = {}

    # 获取根目录清单
    root_inventory = self.get_root_inventory()

    # 遍历每个版本目录
    for version in version_dirs:
        # 获取该版本的清单
        version_inventory = self.get_version_inventory(version)

        # 检查是否包含完整清单
        if not version_inventory:
            raise ValueError(f"Version {version} does not contain a complete inventory")

        # 与根清单比较,记录差异
        diffs = {}
        for file_path, checksum in version_inventory.items():
            if file_path not in root_inventory:
                diffs[file_path] = {'status': 'added', 'checksum': checksum}
            elif root_inventory[file_path] != checksum:
                diffs[file_path] = {
                    'status': 'modified',
                    'old_checksum': root_inventory[file_path],
                    'new_checksum': checksum
                }

        for file_path in root_inventory:
            if file_path not in version_inventory:
                diffs[file_path] = {
                    'status': 'deleted',
                    'old_checksum': root_inventory[file_path]
                }

        # 存储该版本的差异
        if diffs:
            version_diffs[version] = diffs

    return version_diffs

def amend_bzparams(self, params, bug_ids):
    """
    修改 Bugzilla 参数
    """
    if not params or not bug_ids:
        return params

    # Convert single bug_id to list
    if isinstance(bug_ids, (int, str)):
        bug_ids = [str(bug_ids)]
    else:
        bug_ids = [str(bug_id) for bug_id in bug_ids]

    # Add bug_ids to params
    if len(bug_ids) == 1:
        params['id'] = bug_ids[0]
    else:
        params['ids'] = ','.join(bug_ids)

    return params

